import{_ as n}from"./vs-launch-69ffd32b.js";import{_ as l}from"./plugin-vue_export-helper-c27b6911.js";import{r as i,o,c as r,b as t,d as e,e as m,a}from"./app-47fd2188.js";const k="/assets/images/vasvari/csharp/vs-installer-workloads.png",d={},z=a('<h1 id="ide-beszerzese" tabindex="-1"><a class="header-anchor" href="#ide-beszerzese" aria-hidden="true">#</a> IDE beszerzése</h1><div class="hint-container note"><p class="hint-container-title">Röviden</p><p>A programozás bonyolult dolog de egy integrált fejlesztői környezet (<em>IDE</em>) segítségével könnyebbé tehetjük a programozói életetünket. A <strong>Visual Studio</strong> a legelterjedtebb <em>IDE</em> a <strong>C#</strong> programozáshoz. A <strong>Visual Studio Community</strong> ingyenes, számos funkcióval rendelkezik, és kezdőknek ajánlott. Más <strong>C#</strong> <em>IDE</em>-k is léteznek, például a <em>Visual Studio Code</em> és a <em>JetBrains Rider</em>.</p></div><p>A modernkori programozás összetett és kihívást jelentő feladat,de a programozónak nem kell egyedül küzdenie.<br> A programozók széles körű eszközgyűjteménnyel dolgoznak, hogy segítsék őket a munkájuk elvégzésében. Az integrált fejlesztőkörnyezet (<em>IDE</em>) olyan program, amely ezeket az eszközöket egyetlen alkalmazásban integrálja, és a programozási folyamat egyszerűsítésére szolgál. Az <em>IDE</em> a programozást úgy segíti, mint a <em>Microsoft Word</em> a szövegszerkesztést vagy az <em>Adobe Photoshop</em> a képszerkesztést. A legtöbb programozó egy <em>IDE</em>-t használ a munkája során.</p><p>Többféle <strong>C#</strong> fejlesztőkörnyezet közül lehet választani (<em>vagy akár anélkül is dolgozhatunk, hogy közvetlenül a nyers eszközöket használjuk, de ezt nem javaslom...</em>). Most megnézzük a legnépszerűbb <strong>C#</strong> <em>IDE</em>-ket, és megbeszéljük azok előnyeit és hátrányait.</p><p>Sajnálatos módon minden <em>IDE</em> más, és mindegyiket nem tudom bemutatni. Mellesleg ez az anyag a <strong>C#</strong> nyelvre összpontosít, nem egy adott IDE-re, a feladatokat a Visual Studio segítségével oldjuk majd meg. Viszont nyugodtan használhatsz más <em>IDE</em>-t is. A <strong>C#</strong> nyelv maga ugyanaz, függetlenül attól, hogy melyik <em>IDE</em>-t választod, de némi különbséget tapasztalhatsz használat során. Általában az eljárás intuitív, és ha a kísérletezés nem vezet eredményre, a <em>Google</em> általában segíthet. 😊</p><h2 id="az-ide-k-osszehasonlitasa" tabindex="-1"><a class="header-anchor" href="#az-ide-k-osszehasonlitasa" aria-hidden="true">#</a> Az IDE-k összehasonlítása</h2><p>Több kiemelkedő IDE közül választhat.</p><h3 id="visual-studio" tabindex="-1"><a class="header-anchor" href="#visual-studio" aria-hidden="true">#</a> Visual Studio</h3><p>A Microsoft <em>Visual Studio</em> a legtöbb <strong>C#</strong>-fejlesztő által használt, jól bevált IDE. A <em>Visual Studio</em> még a <strong>C#</strong>-nál is régebbi, bár azóta jelentősen sokat fejlődött.</p><p>Az itt tárgyalt IDE-k közül ez a legfunkciógazdagabb és leghatékonyabb, bár van egy jelentős hátránya: <em>Windows</em>-on működik, de <em>Mac</em>-en és <em>Linux</em>-on nem. 😔</p><p>A <em>Visual Studio</em> három különböző kiadásban érhető el:</p><ul><li>Community,</li><li>Professional,</li><li>Enterprise.</li></ul><p>A <em>Community</em> és a <em>Professional</em> kiadások ugyanazzal a szolgáltatáskészlettel rendelkeznek, míg az <em>Enterprise</em> kibővített funkciókkal rendelkezik néhány extra költség mellett.<br> A <em>Community Edition</em> és a <em>Professional Edition</em> között csak az árban és a licencben van különbség. A <em>Visual Studio Community Edition</em> <strong>ingyenes</strong>, diákoknak, nyílt forráskódú projekteknek és magánszemélyeknek, akár kereskedelmi felhasználásra is.</p><div class="hint-container info"><p class="hint-container-title">A nagyvállalatok nem tartoznak ebbe a kategóriába, és meg kell vásárolni a Professional-t. Ha 250-nél több számítógéppel rendelkezik, éves szinten több mint 1 millió dollárt keres, vagy ötnél több Visual Studio felhasználója van, akkor a Professionalért kell fizetnie. De ez most szinte biztosan nem érinti minket.</p></div><p>A <strong>Visual Studio Community</strong> kiadása az általam ajánlott Windowst használó új <strong>C#</strong> programozók számára.</p><h3 id="visual-studio-code" tabindex="-1"><a class="header-anchor" href="#visual-studio-code" aria-hidden="true">#</a> Visual Studio Code</h3><p>A Microsoft <strong>Visual Studio Code</strong> egy <strong>lightweight</strong> szerkesztő (<em>nem teljes körű IDE</em>), amely <em>Windows</em>, <em>Mac</em> és <em>Linux</em> rendszereken egyaránt működik. A <strong>Visual Studio Code</strong> ingyenes, viszont nem rendelkezik ugyanazzal a kiterjedt funkciókészlettel, mint a <em>Visual Studio</em>, és néhány helyen a korlátozott a funkciókészlete. A <strong>Visual Studio Code</strong> valószínűleg a legjobb választás számodra, ha a <em>Visual Studio</em> nem opció (például <em>Linux</em>-on és <em>Mac</em>-en), különösen, ha van tapasztalatod a parancssor használatában.</p><h3 id="jetbrains-rider" tabindex="-1"><a class="header-anchor" href="#jetbrains-rider" aria-hidden="true">#</a> JetBrains Rider</h3><p>Az egyetlen <em>nem-Microsoft IDE</em> ezen a listán a <strong>JetBrains</strong> által készített <em>Rider IDE</em>. A <em>Rider</em> viszonylag új, de a <strong>JetBrains</strong> nagy tapasztalattal rendelkezik más nyelvekhez készült <em>IDE</em>-k készítésében. A <em>Rider</em>-nek nincs ingyenes verziója, a legolcsóbb opció évente mintegy 190 euróba kerül. Azonban gazdag funkciókkal rendelkezik, és több platformon használható. Ha van pénzed rá, ez jó választás lehet bármely operációs rendszeren.</p><h3 id="mas-ide-k" tabindex="-1"><a class="header-anchor" href="#mas-ide-k" aria-hidden="true">#</a> Más IDE-k</h3><p>Vannak más <em>IDE</em>-k is, de a legtöbb <strong>C#</strong> programozó a fentiek egyikét használja. Más <em>IDE</em>-k általában sok funkciót nem tartalmaznak, nem jól támogatottak, és kevesebb online segítséggel és dokumentációval rendelkeznek. De ha találsz egy másik <em>IDE</em>-t, ami tetszik, használd nyugodtan azt.</p><h2 id="visual-studio-telepitese" tabindex="-1"><a class="header-anchor" href="#visual-studio-telepitese" aria-hidden="true">#</a> Visual Studio telepítése</h2>',22),g=t("em",null,"Visual Studio",-1),u={href:"https://visualstudio.microsoft.com/downloads",target:"_blank",rel:"noopener noreferrer"},h=t("strong",null,"Visual Studio 2022",-1),p=t("em",null,"Visual Studio",-1),c=t("em",null,"Visual Studio",-1),b=t("strong",null,"Visual Studio Installer",-1),y=a('<p>Amint elkezded telepíteni a <em>Visual Studio</em>-t, meg fogja kérdezni, hogy mely összetevőket szeretnéd telepíteni:</p><figure><img src="'+k+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>Miután mindent feltelepítettünk, a <em>Visual Studio</em> egy hatalmas, mindenre képes óriás lesz. Nem szükséges az összes lehetséges <em>Visual Studio</em> funkció. Valójában most még csak egy kis szeletre lesz szükségünk abból, amit a <em>Visual Studio</em> kínál.</p><p>Telepíthetünk mindent is, ami érdekesnek tűnik, de most csak egy elemet kell telepítenünk. A <strong>Workloads</strong> fülön keressük meg azt, amit <strong>.NET desktop development</strong>-nek hívnak, és kattintsunk rá annak engedélyezéséhez. Ha elfelejted ezt megtenni, mindig újra futtathatod a <em>Visual Studio</em> Installer-t, és megváltoztathatod, hogy milyen összetevőket telepítettél.</p><div class="hint-container warning"><p class="hint-container-title">Figyelem! Ügyeljenünk arra, hogy a megfelelő Workloads-okat telepítsük. Ha nem így teszel, nem fogod tudni használni az összes C# funkciót.</p></div><p>Miután telepítettük a <em>Visual Studio</em>-t, nyissuk meg azt. A <em>Visual Studio</em> meg fogja kérni, hogy jelentkezzünk be egy Microsoft-fiókkal, még az ingyenes <em>Community Edition</em> esetében is. Nem kell bejelentkezned, ha nem akarsz, de lehetővé tesz néhány funkciót - <em>például a beállítások szinkronizálását több eszközön keresztül</em>.</p><p>Ha először telepíted a <em>Visual Studio</em>-t, akkor lehetőséget kapsz a fejlesztési beállítások - <em>billentyűparancsok és színtéma</em> - kiválasztására is. Bármit is választasz, később is megváltoztathatod. Akkor tudjuk, hogy készen vagyunk, amikor elérjük az alábbi indítóképernyőt:</p><figure><img src="'+n+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure>',8);function f(v,j){const s=i("ExternalLinkIcon");return o(),r("div",null,[z,t("p",null,[e("A "),g,e(" Community Edition letölthető a "),t("a",u,[e("https://visualstudio.microsoft.com/downloads"),m(s)]),e(" oldalról. A "),h,e("-es vagy újabb verzióját érdemes letölteni ahhoz, hogy összes funkciót használni tudjuk majd. Vegyük figyelembe, hogy ez nem magát a "),p,e("-t, hanem a "),c,e(" telepítőjét tölti le. A "),b,e(" segítségével testre szabhatjuk, hogy mely komponenseket telepítse. Bármikor, amikor módosítani szeretnénk a rendelkezésre álló funkciókat, futtassuk újra a telepítőt, és végezzük el a kívánt módosításokat.")]),y])}const A=l(d,[["render",f],["__file","lesson2.html.vue"]]);export{A as default};
